<template>
  <VaSidebar v-model="writableVisible" :width="sidebarWidth" :color="color" minimized-width="64px">
    <div class="side-header bg-blue-50 px-5 pt-4 pb-5">
      <img src="/public/transrafael_logo.png" alt="Logo" />
    </div>

    <VaAccordion v-model="value" multiple>
      <VaCollapse v-for="(route, index) in navigationRoutes.routes" :key="index">
        <template #header="{}">
          <VaSidebarItem
            :to="route.children ? undefined : { name: route.name }"
            :active="routeHasActiveChild(route)"
            :active-color="activeColor"
            :text-color="textColor(route)"
            :aria-label="`${route.children ? 'Open category ' : 'Visit'} ${t(route.displayName)}`"
            role="button"
            hover-opacity="0.10"
            @click="route.children ? undefined : showLoading(route.name)"
          >
            <VaSidebarItemContent class="py-3 pr-2 pl-4">
              <VaIcon
                v-if="route.meta.icon"
                aria-hidden="true"
                :name="route.meta.icon"
                size="20px"
                class="material-symbols-outlined"
                :color="iconColor(route)"
              />
              <VaSidebarItemTitle class="flex justify-between items-center text-xs font-semibold leading-3">
                {{ t(route.displayName) }}
                <VaIcon v-if="route.children" :name="arrowDirection(isCollapsed)" size="13px" />
              </VaSidebarItemTitle>
            </VaSidebarItemContent>
          </VaSidebarItem>
        </template>
        <template #body>
          <div v-for="(childRoute, index2) in route.children" :key="index2">
            <VaSidebarItem
              :to="{ name: childRoute.name }"
              :active="isActiveChildRoute(childRoute)"
              :active-color="activeColor"
              :text-color="textColor(childRoute)"
              :aria-label="`Visit ${t(route.displayName)}`"
              hover-opacity="0.10"
              @click="showLoading(childRoute.name)"
            >
              <VaSidebarItemContent class="py-1 pr-2 pl-11">
                <VaSidebarItemTitle class="leading-1 font-semibold text-xs">
                  {{ t(childRoute.displayName) }}
                </VaSidebarItemTitle>
              </VaSidebarItemContent>
            </VaSidebarItem>
          </div>
        </template>
      </VaCollapse>
    </VaAccordion>

    <VaSpacer />

    <div class="side-user-card px-5 flex justify-between gap-1">
      <!-- <VaAvatar size="small" src="https://i.pinimg.com/280x280_RS/08/e9/ba/08e9ba9cbd24db8de0c250570af460a4.jpg" /> -->
      <div>
        <h4 class="text-xs font-bold capitalize cursor-pointer" @click="showProfile = true">{{ username }}</h4>
        <!-- <p>Administrador</p> -->
      </div>
      <VaIcon name="logout" size="16px" class="material-symbols-outlined ml-2 cursor-pointer" @click="doLogout" />
    </div>

    <hr class="mt-5" />

    <VaAccordion v-if="userStore.can_edit">
      <VaSidebarItem to="/settings">
        <VaSidebarItemContent>
          <VaIcon name="settings" size="20px" class="material-symbols-outlined" />
          <VaSidebarItemTitle class="flex justify-between items-center text-xs font-semibold">
            Configuración
          </VaSidebarItemTitle>
        </VaSidebarItemContent>
      </VaSidebarItem>
    </VaAccordion>
  </VaSidebar>

  <VaModal v-model="showProfile" hide-default-actions size="400px" close-button blur no-dismiss>
    <div class="mt-4">
      <UpdatePassword @close="closeUpdatePassword" />
    </div>
  </VaModal>
</template>
<script lang="ts">
import { defineComponent, watch, ref, computed } from 'vue'
import { useRoute, useRouter } from 'vue-router'

import { useI18n } from 'vue-i18n'
import { useColors, useToast } from 'vuestic-ui'

import navigationRoutes, { type INavigationRoute } from './NavigationRoutes'
import { useUserStore } from '../../stores/user-store'
import UpdatePassword from './UpdatePassword.vue'

export default defineComponent({
  name: 'Sidebar',
  components: {
    UpdatePassword,
  },
  props: {
    visible: { type: Boolean, default: true },
    mobile: { type: Boolean, default: false },
  },
  emits: ['update:visible'],
  setup: (props, { emit }) => {
    const { getColor, colorToRgba } = useColors()
    const route = useRoute()
    const router = useRouter()
    const { t } = useI18n()
    const { notify } = useToast()
    const userStore = useUserStore()

    const value = ref<boolean[]>([])

    const writableVisible = computed({
      get: () => props.visible,
      set: (v: boolean) => emit('update:visible', v),
    })

    const closeUpdatePassword = () => {
      showProfile.value = false
    }

    const showLoading = (path: any) => {
      console.log(path, route.path)
    }

    const showProfile = ref(false)

    const isActiveChildRoute = (child: INavigationRoute) => route.name === child.name

    const routeHasActiveChild = (section: INavigationRoute) => {
      if (!section.children) {
        return route.path.endsWith(`${section.name}`)
      }

      return section.children.some(({ name }) => route.path.endsWith(`${name}`))
    }

    const setActiveExpand = () =>
      (value.value = navigationRoutes.routes.map((route: INavigationRoute) => routeHasActiveChild(route)))

    const sidebarWidth = computed(() => (props.mobile ? '100vw' : '220px'))
    const color = computed(() => getColor('background-secondary'))
    const username = computed(() => userStore.name)
    const activeColor = computed(() => colorToRgba(getColor('focus'), 0.1))

    const iconColor = (route: INavigationRoute) => (routeHasActiveChild(route) ? 'primary' : 'secondary')
    const textColor = (route: INavigationRoute) => (routeHasActiveChild(route) ? 'primary' : 'textPrimary')
    const arrowDirection = (state: boolean) => (state ? 'va-arrow-up' : 'va-arrow-down')

    const doLogout = () => {
      localStorage.clear()
      notify({ message: 'Cerraste sesión', color: 'warning' })
      router.push('/auth').then(() => window.location.reload())
    }

    const isCollapsed = ref(false)

    watch(() => route.fullPath, setActiveExpand, { immediate: true })

    return {
      writableVisible,
      sidebarWidth,
      value,
      color,
      activeColor,
      navigationRoutes,
      username,
      userStore,
      routeHasActiveChild,
      isActiveChildRoute,
      t,
      showProfile,
      iconColor,
      textColor,
      arrowDirection,
      doLogout,
      closeUpdatePassword,
      isCollapsed,
      showLoading,
    }
  },
})
</script>
