import { createRouter, createWebHistory, RouteRecordRaw } from 'vue-router'

import AuthLayout from '../layouts/AuthLayout.vue'
import AppLayout from '../layouts/AppLayout.vue'
import { useUserStore } from '../stores/user-store'

const routes: Array<RouteRecordRaw> = [
  {
    path: '/:pathMatch(.*)*',
    redirect: { name: 'dashboard' },
  },
  {
    name: 'admin',
    path: '/',
    beforeEnter: (to, from, next) => {
      const lData = localStorage.getItem('__user')
      const uToken = localStorage.getItem('__token')
      if (lData && uToken) {
        next()
      } else {
        return next('/auth')
      }
    },
    component: AppLayout,
    redirect: { name: 'oportunities' },
    children: [
      {
        name: 'dashboard',
        path: 'dashboard',
        redirect: { name: 'oportunities.list' },
        // component: () => import('../pages/admin/dashboard/Dashboard.vue'),
      },
      {
        name: 'settings',
        path: 'settings',
        beforeEnter: (to, from, next) => {
          const user = useUserStore()
          if (user.can_edit) {
            next()
          } else {
            return next('/dashboard')
          }
        },
        component: () => import('../pages/settings/Settings.vue'),
        redirect: { name: 'settings.general' },
        children: [
          {
            name: 'settings.general',
            path: 'general',
            component: () => import('../pages/settings/General.vue'),
          },
          {
            name: 'settings.masters',
            path: 'masters',
            component: () => import('../pages/settings/Masters.vue'),
          },
          {
            name: 'settings.users',
            path: 'users',
            component: () => import('../pages/settings/Users.vue'),
          },
        ],
      },
      {
        name: 'contacts',
        path: 'contacts',
        component: () => import('../pages/customers/CustomersPage.vue'),
        children: [
          {
            name: 'contacts.list',
            path: 'list',
            component: () => import('../pages/customers/pages/ListCustomers.vue'),
          },
          {
            name: 'contacts.locked',
            path: 'locked',
            component: () => import('../pages/customers/pages/ListArchives.vue'),
          },
          {
            name: 'contacts.new',
            path: 'new',
            component: () => import('../pages/customers/pages/NewCustomer.vue'),
          },
          {
            name: 'contacts.juridics',
            path: 'juridics',
            component: () => import('../pages/customers/pages/ListCompanies.vue'),
          },
        ],
      },
      {
        name: 'oportunities',
        path: 'oportunities',
        component: () => import('../pages/oportunities/OportunitiesPage.vue'),
        redirect: { name: 'oportunities.list' },
        children: [
          {
            name: 'oportunities.list',
            path: 'list',
            component: () => import('../pages/oportunities/pages/ListOportunities.vue'),
          },
          {
            name: 'oportunities.new',
            path: 'new',
            component: () => import('../pages/oportunities/pages/NewOportunity.vue'),
          },
        ],
      },
      {
        name: 'orders',
        path: 'orders',
        component: () => import('../pages/orders/OrdersPage.vue'),
        redirect: { name: 'orders.list' },
        children: [
          {
            name: 'orders.list',
            path: 'list',
            component: () => import('../pages/orders/pages/ListOrders.vue'),
          },
          {
            name: 'orders.view',
            path: 'view/:id',
            component: () => import('../pages/orders/pages/ViewOrder.vue'),
          },
        ],
      },
    ],
  },
  {
    path: '/auth',
    component: AuthLayout,
    beforeEnter: (to, from, next) => {
      const lData = localStorage.getItem('__user')
      const uToken = localStorage.getItem('__token')
      if (lData && uToken) {
        return next('/dashboard')
      } else {
        return next()
      }
    },
    children: [
      {
        name: 'login',
        path: 'login',
        component: () => import('../pages/auth/Login.vue'),
      },
      {
        path: '',
        redirect: { name: 'login' },
      },
    ],
  },
  {
    name: '404',
    path: '/404',
    component: () => import('../pages/404.vue'),
  },
]

const router = createRouter({
  history: createWebHistory(import.meta.env.BASE_URL),
  scrollBehavior(to, from, savedPosition) {
    if (savedPosition) {
      return savedPosition
    }
    // For some reason using documentation example doesn't scroll on page navigation.
    if (to.hash) {
      return { el: to.hash, behavior: 'smooth' }
    } else {
      window.scrollTo(0, 0)
    }
  },
  routes,
})

export default router
